/*
 * Web Push handlers for the service worker (BACKLOG.md #23).
 *
 * The app's service worker is generated by vite-plugin-pwa (Workbox) for the
 * offline app shell; Workbox has no notion of push, so this file adds the two
 * listeners it needs and is pulled in via `workbox.importScripts` in
 * `vite.config.ts`. Keeping it a plain, dependency-free script (served from
 * `public/`) means the generated worker stays untouched.
 *
 * The server sends a JSON payload built by `server/push/notifier.ts`:
 *   { title, body, tag, data: { gameId, kind, ... } }
 */

self.addEventListener('push', (event) => {
  let payload = {};
  if (event.data) {
    try {
      payload = event.data.json();
    } catch {
      // A non-JSON push (unexpected) still surfaces its text as the body.
      payload = { body: event.data.text() };
    }
  }

  const title = payload.title || 'Manhunt';
  const options = {
    body: payload.body || '',
    tag: payload.tag,
    // Coalesce repeats under the same tag, but still alert on the newer one.
    renotify: Boolean(payload.tag),
    icon: '/pwa-192x192.png',
    badge: '/pwa-192x192.png',
    data: payload.data || {},
  };

  event.waitUntil(self.registration.showNotification(title, options));
});

self.addEventListener('notificationclick', (event) => {
  event.notification.close();
  event.waitUntil(
    (async () => {
      // Focus an existing app window if one is open; otherwise open a new one.
      const windows = await self.clients.matchAll({ type: 'window', includeUncontrolled: true });
      for (const client of windows) {
        if ('focus' in client) return client.focus();
      }
      if (self.clients.openWindow) return self.clients.openWindow('/');
      return undefined;
    })(),
  );
});
